### 2. Create `Views/Stream/StreamHudView.swift`

```swift
import SwiftUI

/// StreamHudView shows real-time streaming statistics.
///
/// Displays:
/// - Connection status badge (● LIVE / ● CONNECTING / ● RECONNECTING)
/// - Stream duration (HH:MM:SS)
/// - Current resolution
/// - Current bitrate (X.X Mbps)
/// - Current FPS
/// - Recording indicator (● REC)
/// - Thermal warning badge (🌡️ when quality degraded)
struct StreamHudView: View {
    @ObservedObject var viewModel: StreamViewModel

    var body: some View {
        HStack(spacing: 12) {
            // Status badge
            statusBadge

            // Duration
            Text(viewModel.formattedDuration)
                .monospacedDigit()

            Spacer()

            // Stats (only shown when streaming)
            if viewModel.isStreaming {
                Text(viewModel.streamStats.resolution)
                Text(viewModel.formattedBitrate)
                Text("\(Int(viewModel.streamStats.fps)) fps")
            }

            // Thermal warning
            if viewModel.showThermalWarning {
                Image(systemName: "thermometer.high")
                    .foregroundColor(.orange)
            }

            // Recording indicator
            if viewModel.streamStats.isRecording {
                HStack(spacing: 4) {
                    Circle().fill(.red).frame(width: 8, height: 8)
                    Text("REC")
                }
            }
        }
        .font(.system(size: 13, weight: .medium, design: .monospaced))
        .foregroundColor(.white)
        .padding(.horizontal, 12)
        .padding(.vertical, 8)
        .background(.ultraThinMaterial.opacity(0.8))
        .cornerRadius(8)
    }

    private var statusBadge: some View { ... }
}
```

